INSERT INTO public.reports (id, review_id, summary, overall_rag_status, compliance_score, areas_followed, gaps_identified, recommendations, action_items, pdf_path, markdown_path, approval_status, requires_approval, created_at, approved_at, autonomous_review_job_id) VALUES (2, 2, 'Review completed. 54 green / 14 amber / 10 red out of 103 items. Compliance score: 52.43%%.', 'amber', 52.43, '["APIs, Integrations & Messaging", "AI Adoption", "Operational Readiness & Reliability", "Compliance & Governance", "Architecture & Design", "Data & Storage Design", "Code Quality & Standards", "Testing & Coverage", "Technical Documentation", "Performance, Scalability & Resilience", "DevSecOps", "Environments & Infrastructure", "Security Architecture"]', '[{"area": "Architecture & Design", "question": "Who is responsible for the architecture and design ? (If Reflections, who is the named person ? If not Reflections, belo", "rag": "red"}, {"area": "Architecture & Design", "question": "Are architectural decisions and trade-offs documented and aligned with business and technical requirements?", "rag": "red"}, {"area": "Technical Documentation", "question": "Is system design and architecture documentation complete, accurate and version-controlled?", "rag": "red"}, {"area": "Technical Documentation", "question": "Are installation, deployment and configuration steps clearly documented and validated on a clean environment?", "rag": "red"}, {"area": "Technical Documentation", "question": "Are known issues, limitations and technical debt items documented with owners and target dates?", "rag": "amber"}, {"area": "Data & Storage Design", "question": "Are indexing, partitioning and sharding strategies adequate for expected scale and query patterns?", "rag": "red"}, {"area": "Data & Storage Design", "question": "Is database security in place (RBAC, least privilege, encryption at rest, network controls, masking where needed)?", "rag": "amber"}, {"area": "Data & Storage Design", "question": "Is replication or high availability configured where required?", "rag": "red"}, {"area": "Security Architecture", "question": "Is authorization based on least privilege using well-defined roles and permissions (RBAC/ABAC)?", "rag": "red"}, {"area": "Security Architecture", "question": "Are secrets stored in an approved secrets vault and never hardcoded or committed to source control?", "rag": "red"}, {"area": "Security Architecture", "question": "Are checks in place for common vulnerabilities (XSS, SQL injection, CSRF, SSRF, insecure deserialization, etc.)?", "rag": "amber"}, {"area": "Code Quality & Standards", "question": "Are static analysis tools and linters enabled and free of critical issues before merging?", "rag": "red"}, {"area": "Testing & Coverage", "question": "Are automated test suites integrated with CI/CD and run on every build or pull request for critical components?", "rag": "red"}, {"area": "DevSecOps", "question": "Is infrastructure-as-code (Terraform, ARM/Bicep, CloudFormation, Ansible, Helm, etc.) used where applicable?", "rag": "amber"}, {"area": "DevSecOps", "question": "Are backups, restore procedures and DR runbooks validated through regular drills or simulations?", "rag": "amber"}, {"area": "DevSecOps", "question": "Are CI/CD tools themselves secured with access control, audit trails and least-privilege permissions?", "rag": "amber"}, {"area": "Environments & Infrastructure", "question": "Are environments provisioned and updated via IaC and configuration management tools?", "rag": "amber"}, {"area": "Environments & Infrastructure", "question": "Are capacities right-sized with headroom for growth and peak loads, and is auto-scaling used where relevant?", "rag": "amber"}, {"area": "Environments & Infrastructure", "question": "Are recent build or environment failures analyzed with RCA and corrective actions tracked?", "rag": "amber"}, {"area": "Environments & Infrastructure", "question": "Are high-availability and resilience mechanisms in place (clusters, load balancers, multi-AZ or multi-node)?", "rag": "amber"}, {"area": "Environments & Infrastructure", "question": "Are network configurations (VPC/VNet, firewalls, security groups, ingress/egress rules, VPN) reviewed and documented?", "rag": "amber"}, {"area": "Compliance & Governance", "question": "Are licensing requirements for all third-party tools, libraries and platforms understood and compliant?", "rag": "amber"}, {"area": "Compliance & Governance", "question": "Are audit logs enabled for critical business and security events and stored securely with defined retention?", "rag": "amber"}, {"area": "Compliance & Governance", "question": "Are access reviews, segregation of duties and approval workflows in place for privileged operations and changes?", "rag": "amber"}]', '[]', '[]', NULL, NULL, 'pending', true, '2026-03-27 06:24:57.018409', NULL, NULL);
